-- =============================================================================
-- PEMOS Test Data Seed
-- =============================================================================
-- Creates a complete test environment with:
--   - 1 auth user (test@mail.com, role: admin) -- password supplied at runtime
--   - 1 tenant party (PAND - Partido Alianza Nacional Dominicana)
--   - 12 circunscripciones, 22 sectores, 12 recintos, 21 colegios
--   - 40 members (6 coordinadores, 8 multiplicadores, 26 relacionados)
--   - 1 electoral period (Elecciones Generales 2028)
--   - 8 candidates across 5 position types
--   - 27 vote records, 5 actas
--   - 4 schedule events, 8 follow-up records, 4 recinto assignments
--
-- Prerequisites:
--   - All migrations through 20260410000001 applied
--   - Geographic seed data (provincias, municipios) already loaded
--
-- Usage:
--   The dev test user is already provisioned in the deployed Supabase project
--   and is normally NOT recreated by this seed. If you need to re-run this
--   seed against a fresh local/dev database, supply the test user password
--   via the `app.test_user_password` GUC before executing this file. Examples:
--
--     # psql one-off (set for the session, then run the seed):
--     psql "$DATABASE_URL" \
--       -v ON_ERROR_STOP=1 \
--       -c "SET app.test_user_password = 'choose-a-strong-local-password';" \
--       -f supabase/seed-test-data.sql
--
--     # or export it once and let the SET below pick it up:
--     PGOPTIONS="-c app.test_user_password=choose-a-strong-local-password" \
--       psql "$DATABASE_URL" -f supabase/seed-test-data.sql
--
--   Never commit a real password literal here. If the GUC is unset, the seed
--   generates a random password — you will then need to reset it via the
--   Supabase auth admin API before logging in.
--
-- Tenant ID: a0000000-0000-0000-0000-000000000001
-- Auth User ID: c0000000-0000-0000-0000-000000000001
-- Usuario ID: d0000000-0000-0000-0000-000000000001
-- Party (PAND) ID: b0000000-0000-0000-0000-000000000001
-- =============================================================================

-- =============================================================================
-- CLEANUP (idempotent - safe to re-run)
-- =============================================================================
DELETE FROM seguimiento_miembros WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM asignacion_recintos WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM actas WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM candidato_votos WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM candidatos WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM periodos_electorales WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM colegios WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM miembros WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM usuarios WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM auth.identities WHERE user_id = 'c0000000-0000-0000-0000-000000000001';
DELETE FROM auth.users WHERE id = 'c0000000-0000-0000-0000-000000000001';
DELETE FROM recintos WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM sectores WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM circunscripciones WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';
DELETE FROM partidos WHERE id = 'b0000000-0000-0000-0000-000000000001';
DELETE FROM cronogramas WHERE tenant_id = 'a0000000-0000-0000-0000-000000000001';


-- =============================================================================
-- STEP 1: Tenant Party
-- =============================================================================
